<!DOCTYPE html>
<html lang="fr" data-mode="night">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>Renaît-Sens — Bienvenue dans la Caravane</title>
<link href="https://fonts.googleapis.com/css2?family=Cinzel:wght@400;500&family=Cormorant+Garamond:ital,wght@0,300;0,400;1,300;1,400&family=Philosopher:ital,wght@0,400;1,400&display=swap" rel="stylesheet">
<style>
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth}
[data-mode="night"]{
  --bg:#03020A;--bg2:#07060F;
  --txt:rgba(245,235,210,.95);--txt2:rgba(245,235,210,.65);
  --or:#C9A96E;--or-vif:#E8C97A;--or-sombre:#8B6530;
  --or-glow:rgba(201,169,110,.4);
  --card:rgba(7,6,15,.85);--border:rgba(201,169,110,.18);
}
[data-mode="noon"]{
  --bg:#FAF7F0;--bg2:#F2EDE2;
  --txt:#1A0A00;--txt2:rgba(40,20,0,.65);
  --or:#8B5020;--or-vif:#A06030;--or-sombre:#6B3A10;
  --or-glow:rgba(139,80,32,.3);
  --card:rgba(255,252,245,.95);--border:rgba(92,58,16,.15);
}
body{font-family:'Cormorant Garamond',Georgia,serif;background:var(--bg);color:var(--txt);
  min-height:100vh;overflow-x:hidden;cursor:none;transition:background 1.2s,color 1s;}
body::before{content:'';position:fixed;top:0;left:0;right:0;height:1px;
  background:linear-gradient(90deg,transparent,var(--or-sombre),var(--or-vif),var(--or-sombre),transparent);
  z-index:9999;pointer-events:none;}
.grain{position:fixed;inset:0;z-index:1;pointer-events:none;opacity:.025;
  background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='.75' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  background-size:200px}
.cur{position:fixed;width:7px;height:7px;background:var(--or);border-radius:50%;
  pointer-events:none;z-index:9999;transform:translate(-50%,-50%);box-shadow:0 0 10px var(--or-glow);}
.cur-r{position:fixed;width:28px;height:28px;border:1px solid rgba(201,169,110,.35);
  border-radius:50%;pointer-events:none;z-index:9998;transform:translate(-50%,-50%);}
::-webkit-scrollbar{width:3px}
::-webkit-scrollbar-track{background:var(--bg)}
::-webkit-scrollbar-thumb{background:linear-gradient(180deg,var(--or-sombre),var(--or),var(--or-sombre))}

.msw-wrap{position:fixed;bottom:2rem;left:50%;transform:translateX(-50%);z-index:500;
  display:flex;gap:.35rem;background:rgba(0,0,0,.35);backdrop-filter:blur(14px);
  border:1px solid rgba(255,255,255,.08);border-radius:50px;padding:.3rem;}
[data-mode="noon"] .msw-wrap{background:rgba(255,255,255,.5);border-color:rgba(92,58,16,.2)}
.msw{border:none;border-radius:50px;background:transparent;padding:.3rem .78rem;
  font-family:'Philosopher',serif;font-size:.65rem;letter-spacing:.12em;text-transform:uppercase;
  cursor:pointer;transition:all .3s;color:rgba(245,235,210,.45);}
[data-mode="noon"] .msw{color:rgba(15,7,0,.45)}
.msw.on{background:rgba(201,169,110,.18);color:var(--or-vif)!important;}
[data-mode="noon"] .msw.on{background:rgba(92,58,16,.14);color:#5a3010!important;}

.page{min-height:100vh;display:grid;grid-template-columns:1fr 1fr;position:relative;z-index:10;}

.page-left{position:relative;overflow:hidden;
  background:url('data:image/jpeg;base64,') center/cover no-repeat;}
.page-left::after{content:'';position:absolute;inset:0;
  background:linear-gradient(90deg,rgba(3,2,10,.2) 0%,rgba(3,2,10,.85) 100%),
             linear-gradient(180deg,rgba(3,2,10,.6) 0%,transparent 30%,transparent 70%,rgba(3,2,10,.8) 100%);}
.left-badge{position:absolute;bottom:3rem;left:2.5rem;z-index:2;}
.left-badge .line{width:40px;height:1px;background:linear-gradient(90deg,var(--or),transparent);margin-bottom:.8rem;}
.left-badge .label{font-family:'Cinzel',serif;font-size:.58rem;letter-spacing:.5em;
  text-transform:uppercase;color:var(--or);display:block;margin-bottom:.3rem;
  text-shadow:0 0 20px var(--or-glow);}
.left-badge .name{font-family:'Cinzel',serif;font-size:1.5rem;font-weight:400;
  color:#fff;text-shadow:0 2px 20px rgba(0,0,0,.9);line-height:1.1;}

.page-right{background:var(--bg2);display:flex;flex-direction:column;
  align-items:center;justify-content:center;padding:4rem 3rem;
  border-left:1px solid var(--border);transition:background 1.2s;position:relative;}
.page-right::before{content:'';position:absolute;top:0;left:0;bottom:0;width:1px;
  background:linear-gradient(180deg,transparent,var(--or-sombre) 20%,var(--or) 50%,var(--or-sombre) 80%,transparent);
  opacity:.4;}

.success-icon{width:80px;height:80px;border-radius:50%;border:1px solid var(--or);
  background:rgba(201,169,110,.08);display:flex;align-items:center;justify-content:center;
  font-size:2rem;margin-bottom:2rem;box-shadow:0 0 30px var(--or-glow);
  animation:pulse-or 2.5s ease-in-out infinite;position:relative;}
.success-icon::after{content:'';position:absolute;inset:-8px;border-radius:50%;
  border:1px solid rgba(201,169,110,.2);animation:pulse-ring 2.5s ease-in-out infinite;}
@keyframes pulse-or{0%,100%{box-shadow:0 0 20px rgba(201,169,110,.3)}50%{box-shadow:0 0 40px rgba(201,169,110,.6)}}
@keyframes pulse-ring{0%,100%{transform:scale(1);opacity:.4}50%{transform:scale(1.1);opacity:.1}}

.eyebrow{font-family:'Cinzel',serif;font-size:.6rem;letter-spacing:.55em;
  text-transform:uppercase;color:var(--or);margin-bottom:1rem;display:block;}
.success-title{font-family:'Cinzel',serif;font-size:clamp(1.6rem,3vw,2.4rem);
  font-weight:400;line-height:1.2;color:var(--txt);text-align:center;margin-bottom:.5rem;}
.success-title em{display:block;font-family:'Cormorant Garamond',serif;
  font-style:italic;font-weight:300;font-size:.5em;color:var(--or);
  letter-spacing:.18em;margin-top:.5rem;}

.sep{display:flex;align-items:center;gap:1rem;margin:1.8rem 0;width:100%;max-width:420px;}
.sep::before,.sep::after{content:'';flex:1;height:1px;
  background:linear-gradient(90deg,transparent,var(--or-sombre),transparent);}
.sep-gem{width:7px;height:7px;background:var(--or);transform:rotate(45deg);
  flex-shrink:0;box-shadow:0 0 8px var(--or-glow);}

.quote{font-size:1.1rem;font-style:italic;font-weight:300;color:var(--txt2);
  line-height:1.85;max-width:400px;margin-bottom:2rem;
  border-left:2px solid var(--or);padding-left:1.2rem;}

.traversee-badge{display:inline-flex;align-items:center;gap:.6rem;
  padding:.5rem 1.4rem;margin-bottom:2rem;border-radius:2px;
  font-family:'Cinzel',serif;font-size:.65rem;letter-spacing:.35em;text-transform:uppercase;}
.badge-bronze{color:#FFB347;border:1px solid rgba(205,133,63,.4);
  background:linear-gradient(135deg,rgba(90,40,10,.5),rgba(160,82,45,.3));
  text-shadow:0 0 12px rgba(255,160,50,.6);}
.badge-argent{color:#D8EAF5;border:1px solid rgba(120,160,210,.35);
  background:linear-gradient(135deg,rgba(20,30,50,.5),rgba(60,90,130,.3));
  text-shadow:0 0 12px rgba(160,210,245,.5);}
.badge-or{color:#FFD700;border:1px solid rgba(255,215,0,.4);
  background:linear-gradient(135deg,rgba(42,24,0,.5),rgba(107,69,0,.35));
  text-shadow:0 0 18px rgba(255,215,0,.9);animation:or-pulse 2.5s ease-in-out infinite;}
@keyframes or-pulse{0%,100%{text-shadow:0 0 18px rgba(255,215,0,.9)}50%{text-shadow:0 0 32px rgba(255,215,0,1)}}

.steps-box{width:100%;max-width:420px;border:1px solid var(--border);
  background:var(--card);padding:1.5rem;margin-bottom:2rem;backdrop-filter:blur(12px);}
.steps-title{font-family:'Cinzel',serif;font-size:.6rem;letter-spacing:.35em;
  text-transform:uppercase;color:var(--or);opacity:.85;display:block;margin-bottom:1.2rem;}
.step-item{display:flex;align-items:flex-start;gap:1rem;padding:.7rem 0;
  border-bottom:1px solid rgba(201,169,110,.08);}
.step-item:last-child{border-bottom:none;}
.step-num{font-family:'Cinzel',serif;font-size:.75rem;color:var(--or);
  flex-shrink:0;min-width:20px;font-weight:600;}
.step-txt{font-size:.92rem;font-style:italic;font-weight:300;color:var(--txt2);line-height:1.6;}
.step-txt strong{font-style:normal;color:var(--txt);font-weight:400;}

.btns{display:flex;gap:1rem;flex-wrap:wrap;justify-content:center;margin-top:.5rem;}
.btn-or{display:inline-flex;align-items:center;gap:.5rem;padding:.85rem 2rem;
  font-family:'Cinzel',serif;font-size:.72rem;letter-spacing:.22em;text-transform:uppercase;
  text-decoration:none;color:var(--or-vif);border:1px solid var(--or);
  background:transparent;position:relative;overflow:hidden;transition:all .5s;cursor:pointer;}
.btn-or::before{content:'';position:absolute;inset:0;
  background:linear-gradient(135deg,rgba(201,169,110,0),rgba(201,169,110,.18),rgba(201,169,110,0));
  transform:translateX(-100%);transition:transform .6s;}
.btn-or:hover::before{transform:translateX(100%);}
.btn-or:hover{background:rgba(201,169,110,.12);box-shadow:0 0 28px var(--or-glow);transform:translateY(-1px);}
.btn-ghost{display:inline-flex;align-items:center;gap:.5rem;padding:.85rem 2rem;
  font-family:'Cinzel',serif;font-size:.72rem;letter-spacing:.22em;text-transform:uppercase;
  text-decoration:none;color:var(--txt2);border:1px solid var(--border);
  background:transparent;transition:all .4s;cursor:pointer;}
.btn-ghost:hover{border-color:var(--or);color:var(--or-vif);}

.tva-note{font-size:.75rem;font-style:italic;color:rgba(201,169,110,.45);
  text-align:center;margin-top:1.5rem;letter-spacing:.05em;}

@media(max-width:900px){
  .page{grid-template-columns:1fr;}
  .page-left{height:40vh;}
  .page-right{padding:3rem 1.5rem;}
  .btns{flex-direction:column;align-items:center;}
}
</style>
</head>
<body>
<div class="cur" id="cur"></div>
<div class="cur-r" id="cur-r"></div>
<div class="grain"></div>

<div class="msw-wrap">
  <button class="msw on" data-m="night" onclick="setMode('night')">🌙 Nuit</button>
  <button class="msw"    data-m="noon"  onclick="setMode('noon')">🌞 Jour</button>
</div>

<div class="page">

  {{-- GAUCHE — PHOENIX --}}
